// ===================================================
// هنا تضع العملية التي تحتاج اعتماد صالح
// مثال: تقرير صحة النظام اليومي
// ===================================================

const now = new Date();
const dateStr = now.toLocaleDateString('ar-SA', {
  weekday: 'long',
  year: 'numeric',
  month: 'long',
  day: 'numeric'
});
const timeStr = now.toLocaleTimeString('ar-SA', {
  hour: '2-digit',
  minute: '2-digit',
  timeZone: 'Asia/Riyadh'
});

// --- مثال: ملخص العمليات المعلقة ---
const pendingActions = [
  { id: 'ACT-001', type: 'تحديث قاعدة المعرفة', detail: 'إضافة 12 وثيقة جديدة إلى saleh_knowledge', risk: 'منخفض' },
  { id: 'ACT-002', type: 'تنظيف البيانات', detail: 'حذف 3 وثائق مكررة من ChromaDB', risk: 'متوسط' }
];

const actionsList = pendingActions.map((a, i) =>
  `${i + 1}. [${a.id}] ${a.type}\n   📄 ${a.detail}\n   ⚠️ مستوى الخطر: ${a.risk}`
).join('\n\n');

const summaryMessage = [
  `🕋 *SaleH SaaS — بوابة الاعتماد اليومية*`,
  `📅 ${dateStr} — ${timeStr}`,
  ``,
  `العمليات التالية تنتظر اعتمادك:`,
  ``,
  actionsList,
  ``,
  `هل تعتمد تنفيذ هذه العمليات؟`
].join('\n');

return [{
  json: {
    message: summaryMessage,
    pending_count: pendingActions.length,
    actions: pendingActions,
    timestamp: now.toISOString(),
    workflow_id: `GATE-${now.getTime()}`
  }
}];

// استقبال رد التيليجرام وتحليله
const body = $json.body || $json;

// callback_data من زر التيليجرام: "APPROVE::GATE-xxx" أو "REJECT::GATE-xxx"
const callbackData = body?.callback_query?.data ||
                     body?.data ||
                     $json?.callback_query?.data ||
                     '';

const [decision, workflowId] = callbackData.split('::');
const approvedBy = body?.callback_query?.from?.first_name || 'صالح';
const respondedAt = new Date().toISOString();

return [{
  json: {
    decision: decision || 'TIMEOUT',
    workflow_id: workflowId || '',
    approved_by: approvedBy,
    responded_at: respondedAt,
    raw_callback: callbackData
  }
}];

// ===================================================
// هنا يُنفَّذ العمل الفعلي بعد الاعتماد
// استبدل هذا بالعملية الحقيقية المطلوبة
// ===================================================

const approvedBy = $('🔍 تحليل الرد').item.json.approved_by;
const respondedAt = $('🔍 تحليل الرد').item.json.responded_at;

// مثال: يمكن هنا استدعاء API لتنفيذ التحديث
// const result = await fetch('http://data_pipeline:8001/process-file/', ...);

console.log(`✅ اعتمد ${approvedBy} في ${respondedAt}`);

return [{
  json: {
    status: 'executed',
    message: `✅ تم تنفيذ العمليات بنجاح`,
    approved_by: approvedBy,
    executed_at: new Date().toISOString()
  }
}];

const decision = $json.decision;
const approvedBy = $json.approved_by;
const respondedAt = $json.responded_at;

let reason = 'رُفضت يدوياً';
if (decision === 'TIMEOUT') reason = 'انتهت مدة الانتظار (24 ساعة) دون رد';

console.log(`❌ العملية لم تُنفَّذ: ${reason}`);

return [{
  json: {
    status: 'rejected',
    reason: reason,
    decision: decision,
    responded_at: respondedAt
  }
}];

